classdef HierarchicalHeightSolver
    %HIERARCHICALHEIGHTSOLVER Coarse-to-fine pairwise height coordinator.
    %
    % Images must already be radiometrically scaled numeric arrays. Geometry
    % stays double precision; matching arrays use WorkingPrecision. The
    % overview uses one exact common grid. Fine stages make the explicit
    % approximation of one local label vector per nonoverlapping tile.
    %
    % Traceability: algo/main.tex Algorithm 1, Eqs. (1)-(2), (52)-(55),
    % (68)-(76), and (121)-(125); long-range workplan C1.1--C1.5.

    properties (SetAccess = private)
        ReferenceCamera
        MovingCamera
        ReferencePyramid
        MovingPyramid
        Factors (1, :) double
        WorkingPrecision (1, 1) string
        OverviewMaximumDimension (1, 1) double
        Decimation (1, 1) double
        IncludeIntermediateLevels (1, 1) logical
    end

    methods
        function obj = HierarchicalHeightSolver( ...
                referenceCamera, movingCamera, referenceImage, ...
                movingImage, options)
            arguments
                referenceCamera (1, 1) {mustBeHierarchyCamera}
                movingCamera (1, 1) {mustBeHierarchyCamera}
                referenceImage (:, :) ...
                    {mustBeNumeric, mustBeReal, mustBeNonempty, ...
                    mustMatchCameraSize(referenceImage, referenceCamera)}
                movingImage (:, :) ...
                    {mustBeNumeric, mustBeReal, mustBeNonempty, ...
                    mustMatchCameraSize(movingImage, movingCamera)}
                options.ReferenceValid (:, :) logical ...
                    {mustMatchImageSize(options.ReferenceValid, ...
                    referenceImage)} = true(size(referenceImage))
                options.MovingValid (:, :) logical ...
                    {mustMatchImageSize(options.MovingValid, ...
                    movingImage)} = true(size(movingImage))
                options.OverviewMaximumDimension (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 1600
                options.Decimation (1, 1) double ...
                    {mustBeFinite, mustBeInteger, ...
                    mustBeGreaterThanOrEqual(options.Decimation, 2)} = 2
                options.IncludeIntermediateLevels (1, 1) logical = false
                options.PyramidFactors (1, :) double ...
                    {mustBeOptionalPyramidFactors} = zeros(1, 0)
                options.WorkingPrecision (1, 1) string ...
                    {mustBeMember(options.WorkingPrecision, ...
                    ["single", "double"])} = "single"
            end

            HeightSweepGeometry(referenceCamera, movingCamera);
            if isempty(options.PyramidFactors)
                combinedSize = [max(size(referenceImage, 1), ...
                    size(movingImage, 1)), max(size(referenceImage, 2), ...
                    size(movingImage, 2))];
                factors = HeightImagePyramid.selectFactors( ...
                    combinedSize, options.OverviewMaximumDimension, ...
                    options.Decimation, IncludeIntermediateLevels= ...
                    options.IncludeIntermediateLevels);
            else
                factors = options.PyramidFactors;
            end
            precision = options.WorkingPrecision;
            obj.ReferenceCamera = referenceCamera;
            obj.MovingCamera = movingCamera;
            obj.ReferencePyramid = HeightImagePyramid( ...
                cast(referenceImage, precision), options.ReferenceValid, ...
                factors);
            obj.MovingPyramid = HeightImagePyramid( ...
                cast(movingImage, precision), options.MovingValid, factors);
            obj.Factors = factors;
            obj.WorkingPrecision = precision;
            obj.OverviewMaximumDimension = options.OverviewMaximumDimension;
            obj.Decimation = options.Decimation;
            obj.IncludeIntermediateLevels = ...
                options.IncludeIntermediateLevels;
        end

        function report = runOverview(obj, heightRangeMetres, options)
            %RUNOVERVIEW Execute the exact scene-wide coarse height sweep.
            arguments
                obj (1, 1) HierarchicalHeightSolver
                heightRangeMetres (1, 2) double ...
                    {mustBeFinite, mustBeIncreasingRange}
                options.TargetProjectedMotionPixels (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 1
                options.GeometrySampleGrid (1, 2) double ...
                    {mustBeFinite, mustBeInteger, ...
                    mustBeGreaterThanOrEqual(options.GeometrySampleGrid, 3)} ...
                    = [17, 17]
                options.DeltaHeightMetres (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.TileSize (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = [256, 256]
                options.LabelBlockSize (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 8
                options.MinimumSupportFraction (1, 1) double ...
                    {mustBeFinite, mustBeGreaterThanOrEqual( ...
                    options.MinimumSupportFraction, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumSupportFraction, 1)} = 0.8
                options.PenaltyPerMetre (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 0.02
                options.MaximumPenalty (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 0.2
                options.DirectionCount (1, 1) double ...
                    {mustBeMember(options.DirectionCount, [4, 8])} = 8
                options.UseParallel (1, 1) logical = true
                options.NumWorkers (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
                options.MaximumPendingTiles (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
                options.RetainCostVolume (1, 1) logical = false
            end

            totalTimer = tic;
            factor = obj.Factors(1);
            referenceLevel = obj.ReferencePyramid.getLevel(factor);
            movingLevel = obj.MovingPyramid.getLevel(factor);
            [referenceCamera, movingCamera] = obj.levelCameras(factor);
            geometry = HeightSweepGeometry(referenceCamera, movingCamera);
            geometryDiagnostic = HierarchicalHeightSolver.sampleGeometry( ...
                geometry, heightRangeMetres, options.GeometrySampleGrid, ...
                options.DeltaHeightMetres);
            labels = HierarchicalHeightSolver.heightLabels( ...
                heightRangeMetres, ...
                geometryDiagnostic.MedianObservabilityPixelsPerMetre, ...
                options.TargetProjectedMotionPixels);
            actualMotion = diff(heightRangeMetres) ./ (numel(labels) - 1) ...
                .* geometryDiagnostic.MedianObservabilityPixelsPerMetre;

            curve = HeightCostCurve(geometry, referenceLevel.Image, ...
                movingLevel.Image, ReferenceValid=referenceLevel.ValidMask, ...
                MovingValid=movingLevel.ValidMask, PrepareGradients=false, ...
                WorkingPrecision=obj.WorkingPrecision);
            dense = DenseHeightSweep(curve);
            costTimer = tic;
            raw = dense.runZnccOptimized(labels, ...
                TileSize=options.TileSize, ...
                LabelBlockSize=options.LabelBlockSize, ...
                StoreCostVolumes=true, UseParallel=options.UseParallel, ...
                NumWorkers=options.NumWorkers, ...
                MaximumPendingTiles=options.MaximumPendingTiles, ...
                WorkingPrecision=obj.WorkingPrecision, ...
                Products=["LabelIndex", "BestCost", "SecondBestCost", ...
                "NeighborCosts", "Margin", "Curvature", ...
                "ValidLabelCount", "Observability", "Correspondence"], ...
                DeltaHeight=options.DeltaHeightMetres, ...
                MinimumSupportFraction=options.MinimumSupportFraction);
            costSeconds = toc(costTimer);

            refinementTimer = tic;
            refined = HeightSublabelRefiner.refine(labels, raw.LabelIndex, ...
                raw.PreviousLabelCost, raw.BestCost, raw.NextLabelCost, ...
                ValidMask=raw.Valid);
            refinedProjection = dense.projectHeightMap( ...
                refined.RefinedHeightMetres, refined.Valid, ...
                DeltaHeight=options.DeltaHeightMetres);
            refined.CorrespondenceXY = refinedProjection.CorrespondenceXY;
            refined.ObservabilityPixelsPerMetre = ...
                refinedProjection.ObservabilityPixelsPerMetre;
            refined.Valid = refinedProjection.Valid;
            refinementSeconds = toc(refinementTimer);

            sgmTimer = tic;
            sgmFull = HeightSgm.aggregateVectorized(raw.CostVolume, labels, ...
                PenaltyPerMetre=options.PenaltyPerMetre, ...
                MaximumPenalty=options.MaximumPenalty, ...
                DirectionCount=options.DirectionCount);
            sgmProjection = dense.projectHeightMap( ...
                sgmFull.HeightMetres, sgmFull.Valid, ...
                DeltaHeight=options.DeltaHeightMetres);
            sgmFull.CorrespondenceXY = sgmProjection.CorrespondenceXY;
            sgmFull.ObservabilityPixelsPerMetre = ...
                sgmProjection.ObservabilityPixelsPerMetre;
            sgmFull.Valid = sgmProjection.Valid;
            sgmSeconds = toc(sgmTimer);

            rawBoundary = raw.Valid & (raw.LabelIndex == 1 ...
                | raw.LabelIndex == numel(labels));
            sgmBoundary = sgmFull.Valid & (sgmFull.LabelIndex == 1 ...
                | sgmFull.LabelIndex == numel(labels));
            warnings = struct( ...
                "RawBoundaryWinner", rawBoundary, ...
                "SgmBoundaryWinner", sgmBoundary, ...
                "InvalidOutput", ~sgmFull.Valid, ...
                "RawBoundaryWinnerFraction", ...
                nnz(rawBoundary) ./ max(nnz(raw.Valid), 1), ...
                "SgmBoundaryWinnerFraction", ...
                nnz(sgmBoundary) ./ max(nnz(sgmFull.Valid), 1), ...
                "Policy", ...
                "diagnostic only; no rejection or interval expansion");

            costVolumeBytes = numel(raw.CostVolume) ...
                .* HierarchicalHeightSolver.precisionBytes( ...
                class(raw.CostVolume));
            if options.RetainCostVolume
                rawResult = raw;
                sgmResult = sgmFull;
            else
                rawResult = raw;
                rawResult.CostVolume = zeros( ...
                    [referenceLevel.ImageSize, 0], obj.WorkingPrecision);
                rawResult.CostVolumeByChannel = struct;
                rawResult.StoreCostVolumes = false;
                sgmResult = HierarchicalHeightSolver.compactSgm(sgmFull);
            end

            report = struct( ...
                "Stage", "scene-wide overview only", ...
                "Pyramid", struct( ...
                "Factors", obj.Factors, ...
                "OverviewFactor", factor, ...
                "ReferenceBaseSize", obj.ReferencePyramid.BaseImageSize, ...
                "MovingBaseSize", obj.MovingPyramid.BaseImageSize, ...
                "ReferenceLevelSize", referenceLevel.ImageSize, ...
                "MovingLevelSize", movingLevel.ImageSize, ...
                "CoordinateMap", "pBase=factor*(pLevel-0.5)+0.5", ...
                "Filter", obj.ReferencePyramid.FilterDescription, ...
                "MaskPolicy", ...
                "filtered mask weight >= 1-64*eps(single)"), ...
                "OverviewInput", struct( ...
                "ReferenceImage", referenceLevel.Image, ...
                "MovingImage", movingLevel.Image, ...
                "ReferenceValid", referenceLevel.ValidMask, ...
                "MovingValid", movingLevel.ValidMask), ...
                "Geometry", geometryDiagnostic, ...
                "HeightRangeMetres", heightRangeMetres, ...
                "HeightLabelsMetres", labels, ...
                "TargetProjectedMotionPixels", ...
                options.TargetProjectedMotionPixels, ...
                "ActualMedianProjectedMotionPixels", actualMotion, ...
                "Raw", rawResult, ...
                "Refined", refined, ...
                "Sgm", sgmResult, ...
                "Warnings", warnings, ...
                "Settings", struct( ...
                "WorkingPrecision", obj.WorkingPrecision, ...
                "TileSize", options.TileSize, ...
                "LabelBlockSize", options.LabelBlockSize, ...
                "MinimumSupportFraction", options.MinimumSupportFraction, ...
                "PenaltyPerMetre", options.PenaltyPerMetre, ...
                "MaximumPenalty", options.MaximumPenalty, ...
                "DirectionCount", options.DirectionCount, ...
                "UseParallel", options.UseParallel, ...
                "NumWorkers", raw.Runtime.NumWorkers, ...
                "RetainCostVolume", options.RetainCostVolume), ...
                "Runtime", struct( ...
                "CostSeconds", costSeconds, ...
                "RefinementSeconds", refinementSeconds, ...
                "SgmSeconds", sgmSeconds, ...
                "TotalSeconds", toc(totalTimer), ...
                "PixelLabelEvaluations", ...
                prod(referenceLevel.ImageSize) .* numel(labels), ...
                "CostVolumeBytes", costVolumeBytes), ...
                "Approximation", ...
                "none beyond overview image filtering; one common exact label grid", ...
                "WorldFrame", referenceCamera.WorldFrame, ...
                "ElevationDatum", referenceCamera.ElevationDatum);
        end

        function plan = prepareNextLevel( ...
                obj, overview, calibrator, options)
            %PREPARENEXTLEVEL Propagate overview fields and plan fine labels.
            %
            % This method does not evaluate image costs. It constructs the
            % first explicit approximation boundary for C1.3.
            arguments
                obj (1, 1) HierarchicalHeightSolver
                overview (1, 1) struct
                calibrator (1, 1) HeightConfidenceCalibrator
                options.TargetProjectedMotionPixels (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.TileSize (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = [256, 256]
                options.GeometrySampleGrid (1, 2) double ...
                    {mustBeFinite, mustBeInteger, ...
                    mustBeGreaterThanOrEqual(options.GeometrySampleGrid, 2)} ...
                    = [3, 3]
                options.DeltaHeightMetres (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.MinimumPropagationSupport (1, 1) double ...
                    {mustBeFinite, mustBeGreaterThanOrEqual( ...
                    options.MinimumPropagationSupport, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumPropagationSupport, 1)} = 0.5
                options.LowConfidenceSigmaPixels (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.ConfidenceSigmaMultiplier (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 1
                options.ConfidenceHeightPercentile (1, 1) double ...
                    {mustBeFinite, mustBeGreaterThanOrEqual( ...
                    options.ConfidenceHeightPercentile, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.ConfidenceHeightPercentile, 100)} = 90
                options.TrajectoryCurvatureDeltaHeightMetres (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 5
            end

            previousFactor = double(overview.Pyramid.OverviewFactor);
            index = find(obj.Factors == previousFactor, 1);
            if isempty(index) || index == numel(obj.Factors)
                error("HierarchicalHeightSolver:NoNextLevel", ...
                    "The overview factor has no finer configured level.");
            end
            nextFactor = obj.Factors(index + 1);
            nextReference = obj.ReferencePyramid.getLevel(nextFactor);
            nextMoving = obj.MovingPyramid.getLevel(nextFactor);
            if ~isequal(size(overview.Sgm.HeightMetres), ...
                    overview.Pyramid.ReferenceLevelSize)
                error("HierarchicalHeightSolver:OverviewSizeMismatch", ...
                    "Overview height size does not match its pyramid provenance.");
            end

            step = median(diff(double(overview.HeightLabelsMetres)));
            confidence = calibrator.predict( ...
                double(overview.Raw.CostMargin), ...
                double(overview.Raw.LocalCurvaturePerMetreSquared) ...
                .* step .^ 2, ...
                double(overview.Raw.ObservabilityPixelsPerMetre));
            sourceValid = logical(overview.Sgm.Valid) ...
                & isfinite(overview.Sgm.HeightMetres);
            [height, inheritedValid, support, clamped] = ...
                HierarchicalHeightSolver.propagateField( ...
                double(overview.Sgm.HeightMetres), sourceValid, ...
                nextReference.ImageSize, previousFactor, nextFactor, ...
                options.MinimumPropagationSupport);
            [sigmaHeight, sigmaValid] = ...
                HierarchicalHeightSolver.propagateField( ...
                confidence.SigmaHeightMetres, confidence.Valid, ...
                nextReference.ImageSize, previousFactor, nextFactor, ...
                options.MinimumPropagationSupport);
            [sigmaPixelPrevious, sigmaPixelValid] = ...
                HierarchicalHeightSolver.propagateField( ...
                confidence.SigmaPixels, confidence.Valid, ...
                nextReference.ImageSize, previousFactor, nextFactor, ...
                options.MinimumPropagationSupport);
            sigmaPixel = sigmaPixelPrevious .* previousFactor ./ nextFactor;
            confidenceValid = sigmaValid & sigmaPixelValid;

            rawBoundary = HierarchicalHeightSolver.propagateWarning( ...
                overview.Warnings.RawBoundaryWinner, ...
                nextReference.ImageSize, previousFactor, nextFactor);
            sgmBoundary = HierarchicalHeightSolver.propagateWarning( ...
                overview.Warnings.SgmBoundaryWinner, ...
                nextReference.ImageSize, previousFactor, nextFactor);
            invalidOutput = HierarchicalHeightSolver.propagateWarning( ...
                overview.Warnings.InvalidOutput, ...
                nextReference.ImageSize, previousFactor, nextFactor) ...
                | ~inheritedValid;
            lowConfidence = confidenceValid ...
                & sigmaPixelPrevious > options.LowConfidenceSigmaPixels;
            confidenceInvalid = ~confidenceValid;

            inheritedValid = inheritedValid & nextReference.ValidMask;
            confidenceValid = confidenceValid & nextReference.ValidMask;
            height(~inheritedValid) = NaN;
            sigmaHeight(~confidenceValid) = NaN;
            sigmaPixel(~confidenceValid) = NaN;
            invalidOutput = invalidOutput | ~nextReference.ValidMask;
            confidenceInvalid = confidenceInvalid | ~nextReference.ValidMask;

            [referenceCamera, movingCamera] = obj.levelCameras(nextFactor);
            geometry = HeightSweepGeometry(referenceCamera, movingCamera);
            tiles = HierarchicalHeightSolver.planTiles( ...
                geometry, height, inheritedValid, sigmaHeight, ...
                confidenceValid, rawBoundary, sgmBoundary, invalidOutput, ...
                lowConfidence, confidenceInvalid, ...
                double(overview.HeightRangeMetres), ...
                double(overview.HeightLabelsMetres), options);

            plan = struct( ...
                "Stage", "propagation and fine tile-label planning only", ...
                "PreviousFactor", previousFactor, ...
                "NextFactor", nextFactor, ...
                "HeightRangeMetres", double(overview.HeightRangeMetres), ...
                "NextReferenceSize", nextReference.ImageSize, ...
                "NextMovingSize", nextMoving.ImageSize, ...
                "CoordinateMap", struct( ...
                "NextToBase", "pBase=fNext*(pNext-0.5)+0.5", ...
                "NextToPrevious", ...
                "pPrevious=(fNext/fPrevious)*(pNext-0.5)+0.5", ...
                "PreviousPixelsPerNextPixel", nextFactor ./ previousFactor, ...
                "BoundaryPolicy", ...
                "linear field interpolation with nearest-coordinate clamping"), ...
                "Inherited", struct( ...
                "HeightMetres", height, ...
                "Valid", inheritedValid, ...
                "InterpolationSupport", support, ...
                "BoundaryCoordinateClamped", clamped, ...
                "SigmaHeightMetres", sigmaHeight, ...
                "SigmaPixels", sigmaPixel, ...
                "ConfidenceValid", confidenceValid, ...
                "RawBoundaryWinner", rawBoundary, ...
                "SgmBoundaryWinner", sgmBoundary, ...
                "InvalidOutput", invalidOutput, ...
                "LowConfidence", lowConfidence, ...
                "ConfidenceInvalid", confidenceInvalid), ...
                "Tiles", tiles, ...
                "Settings", struct( ...
                "TargetProjectedMotionPixels", ...
                options.TargetProjectedMotionPixels, ...
                "TileSize", options.TileSize, ...
                "GeometrySampleGrid", options.GeometrySampleGrid, ...
                "DeltaHeightMetres", options.DeltaHeightMetres, ...
                "MinimumPropagationSupport", ...
                options.MinimumPropagationSupport, ...
                "LowConfidenceSigmaPixels", ...
                options.LowConfidenceSigmaPixels, ...
                "ConfidenceSigmaMultiplier", ...
                options.ConfidenceSigmaMultiplier, ...
                "ConfidenceHeightPercentile", ...
                options.ConfidenceHeightPercentile, ...
                "TrajectoryCurvatureDeltaHeightMetres", ...
                options.TrajectoryCurvatureDeltaHeightMetres), ...
                "Approximation", ...
                "bilinear coarse-field propagation and one common label vector per tile; no fine costs evaluated", ...
                "WorldFrame", referenceCamera.WorldFrame, ...
                "ElevationDatum", referenceCamera.ElevationDatum);
        end

        function result = runFineAdaptive(obj, plan, options)
            %RUNFINEADAPTIVE Evaluate, expand, and rerun local height bands.
            %
            % The first pass evaluates exactly the tile labels recorded by
            % PREPARENEXTLEVEL. Declared warnings then expand affected bands
            % by whole overview-label steps, bounded by the original global
            % range. Only tile cores whose bounds actually grow are rerun.
            %
            % Traceability: algo/main.tex Algorithm 1, lines 4--15 and
            % Eqs. (68)--(76); implementation plan C1 milestone 4.
            arguments
                obj (1, 1) HierarchicalHeightSolver
                plan (1, 1) struct {mustBeFineTilePlan}
                options.LabelBlockSize (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 8
                options.GroupIdenticalBands (1, 1) logical = false
                options.MaximumBandTiles (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 4
                options.MinimumSupportFraction (1, 1) double ...
                    {mustBeFinite, mustBeGreaterThanOrEqual( ...
                    options.MinimumSupportFraction, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumSupportFraction, 1)} = 0.8
                options.DeltaHeightMetres (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.ExpansionCoarseSteps (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 1
                options.CoarseFineDisagreementPixels (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 1
                options.MinimumDisagreementFraction (1, 1) double ...
                    {mustBeFinite, mustBeGreaterThanOrEqual( ...
                    options.MinimumDisagreementFraction, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumDisagreementFraction, 1)} = 0.05
                options.MinimumFineInvalidFraction (1, 1) double ...
                    {mustBeFinite, mustBeGreaterThanOrEqual( ...
                    options.MinimumFineInvalidFraction, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumFineInvalidFraction, 1)} = 0.05
                options.HighTrajectoryCurvatureQuantile (1, 1) double ...
                    {mustBeFinite, mustBeGreaterThanOrEqual( ...
                    options.HighTrajectoryCurvatureQuantile, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.HighTrajectoryCurvatureQuantile, 1)} = 2 / 3
                options.RunSgm (1, 1) logical = false
                options.OutputProfile (1, 1) string ...
                    {mustBeMember(options.OutputProfile, ...
                    ["diagnostic", "compact"])} = "diagnostic"
                options.PenaltyPerMetre (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 0.02
                options.MaximumPenalty (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 0.2
                options.DirectionCount (1, 1) double ...
                    {mustBeMember(options.DirectionCount, [4, 8])} = 8
                options.RetainCostVolumes (1, 1) logical = false
                options.CostStore ...
                    {mustBeOptionalHeightTileStore} = []
                options.AggregateStore ...
                    {mustBeOptionalHeightTileStore} = []
                options.EnabledTriggers (1, :) string ...
                    {mustBeNonempty, mustBeAdaptiveTriggers} = ...
                    ["InheritedRawBoundary", "InheritedSgmBoundary", ...
                    "InheritedInvalidOutput", "InheritedLowConfidence", ...
                    "InheritedConfidenceInvalid", ...
                    "HighTrajectoryCurvature", "UnderDenseLabels", ...
                    "FineBoundaryWinner", "FineInvalidOutput", ...
                    "CoarseFineDisagreement"]
                options.UseParallel (1, 1) logical = true
                options.NumWorkers (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
                options.MaximumPendingTiles (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
                options.EvaluateFullReference (1, 1) logical = false
                options.ReferenceGeometrySampleGrid (1, 2) double ...
                    {mustBeFinite, mustBeInteger, ...
                    mustBeGreaterThanOrEqual( ...
                    options.ReferenceGeometrySampleGrid, 3)} = [17, 17]
            end

            totalTimer = tic;
            HierarchicalHeightSolver.validateAdaptiveStores( ...
                options.CostStore, options.AggregateStore, ...
                options.RunSgm, plan.Tiles, obj.WorkingPrecision);
            factor = double(plan.NextFactor);
            if ~ismember(factor, obj.Factors)
                error("HierarchicalHeightSolver:UnknownFineFactor", ...
                    "The planned next factor is not configured in this solver.");
            end
            referenceLevel = obj.ReferencePyramid.getLevel(factor);
            movingLevel = obj.MovingPyramid.getLevel(factor);
            if ~isequal(referenceLevel.ImageSize, plan.NextReferenceSize) ...
                    || ~isequal(movingLevel.ImageSize, plan.NextMovingSize)
                error("HierarchicalHeightSolver:FinePlanSizeMismatch", ...
                    "The fine plan does not match its configured pyramid level.");
            end
            [referenceCamera, movingCamera] = obj.levelCameras(factor);
            geometry = HeightSweepGeometry(referenceCamera, movingCamera);
            curve = HeightCostCurve(geometry, referenceLevel.Image, ...
                movingLevel.Image, ReferenceValid=referenceLevel.ValidMask, ...
                MovingValid=movingLevel.ValidMask, PrepareGradients=false, ...
                WorkingPrecision=obj.WorkingPrecision);
            dense = DenseHeightSweep(curve);
            hasCostStore = ~isempty(options.CostStore);
            streamedSgm = ~isempty(options.AggregateStore);
            compact = options.OutputProfile == "compact";
            if compact && (~options.RunSgm || ~hasCostStore ...
                    || ~streamedSgm || options.RetainCostVolumes ...
                    || options.EvaluateFullReference)
                error("HierarchicalHeightSolver:IncompatibleCompactProfile", ...
                    "OutputProfile=compact requires RunSgm=true, matching " ...
                    + "CostStore/AggregateStore objects, " ...
                    + "RetainCostVolumes=false, and " ...
                    + "EvaluateFullReference=false.");
            end
            retainCostCells = options.RetainCostVolumes ...
                || (options.RunSgm && ~streamedSgm);
            if compact
                initialProducts = ...
                    ["LabelCount", "LabelIndex", "Correspondence"];
                expansionProducts = "LabelIndex";
                projectionProducts = "Correspondence";
            else
                initialProducts = ["TileIndex", "LabelCount", ...
                    "LabelIndex", "BestCost", "SecondBestCost", ...
                    "NeighborCosts", "Margin", "Curvature", ...
                    "ValidLabelCount", "Observability", ...
                    "Correspondence", "SelectedHeightByChannel"];
                expansionProducts = initialProducts;
                projectionProducts = ...
                    ["Correspondence", "Observability", ...
                    "ValidityDiagnostics"];
            end

            firstTimer = tic;
            initial = dense.runZnccPlannedTiles(plan.Tiles, ...
                LabelBlockSize=options.LabelBlockSize, ...
                GroupIdenticalBands=options.GroupIdenticalBands, ...
                MaximumBandTiles=options.MaximumBandTiles, ...
                StoreCostVolumes=retainCostCells, ...
                UseParallel=options.UseParallel, ...
                NumWorkers=options.NumWorkers, ...
                MaximumPendingTiles=options.MaximumPendingTiles, ...
                WorkingPrecision=obj.WorkingPrecision, ...
                Products=initialProducts, ...
                DeltaHeight=options.DeltaHeightMetres, ...
                MinimumSupportFraction=options.MinimumSupportFraction, ...
                CostStore=options.CostStore);
            firstSeconds = toc(firstTimer);

            inheritedProjection = dense.projectHeightMap( ...
                double(plan.Inherited.HeightMetres), ...
                logical(plan.Inherited.Valid), ...
                DeltaHeight=options.DeltaHeightMetres, ...
                Products=projectionProducts);
            fineBoundary = initial.Valid & (initial.LabelIndex == 1 ...
                | initial.LabelIndex == initial.LabelCount);
            fineInvalid = referenceLevel.ValidMask & ~initial.Valid;
            disagreement = nan(referenceLevel.ImageSize);
            disagreementValid = initial.Valid & inheritedProjection.Valid;
            dx = initial.CorrespondenceXY(:, :, 1) ...
                - inheritedProjection.CorrespondenceXY(:, :, 1);
            dy = initial.CorrespondenceXY(:, :, 2) ...
                - inheritedProjection.CorrespondenceXY(:, :, 2);
            disagreement(disagreementValid) = ...
                hypot(dx(disagreementValid), dy(disagreementValid));
            disagreementWarning = disagreementValid ...
                & disagreement > options.CoarseFineDisagreementPixels;

            [trigger, highCurvature, underDense] = ...
                HierarchicalHeightSolver.adaptiveTriggers( ...
                plan.Tiles, referenceLevel.ValidMask, fineBoundary, ...
                fineInvalid, disagreementWarning, options);
            [finalTiles, trigger] = ...
                HierarchicalHeightSolver.expandTiles( ...
                plan.Tiles, trigger, double(plan.HeightRangeMetres), ...
                options.ExpansionCoarseSteps);
            expandedIds = find(trigger.ExpansionApplied);
            expansionSeconds = 0;
            expansion = struct;
            if ~isempty(expandedIds)
                expansionTimer = tic;
                expansion = dense.runZnccPlannedTiles( ...
                    finalTiles(expandedIds, :), ...
                    LabelBlockSize=options.LabelBlockSize, ...
                    GroupIdenticalBands=options.GroupIdenticalBands, ...
                    MaximumBandTiles=options.MaximumBandTiles, ...
                    StoreCostVolumes=retainCostCells, ...
                    UseParallel=options.UseParallel, ...
                    NumWorkers=options.NumWorkers, ...
                    MaximumPendingTiles=options.MaximumPendingTiles, ...
                    WorkingPrecision=obj.WorkingPrecision, ...
                    Products=expansionProducts, ...
                    DeltaHeight=options.DeltaHeightMetres, ...
                    MinimumSupportFraction=options.MinimumSupportFraction, ...
                    RequireCompletePartition=false, ...
                    ReplaceStoredTiles=hasCostStore, ...
                    CostStore=options.CostStore);
                expansionSeconds = toc(expansionTimer);
            end

            adaptiveRuntime = HierarchicalHeightSolver.mergeAdaptiveRuntime( ...
                initial.Runtime, expansion, finalTiles);
            [finalBoundaryCount, finalRawValidCount] = ...
                HierarchicalHeightSolver.finalRawBoundarySummary( ...
                initial, expansion, finalTiles, expandedIds);
            fineBoundaryBeforeCount = nnz(fineBoundary);
            fineInvalidBeforeCount = nnz(fineInvalid);
            disagreementWarningCount = nnz(disagreementWarning);
            if compact
                raw = struct;
                refined = struct;
                refinementSeconds = 0;
                finalBoundary = false([referenceLevel.ImageSize, 0]);
            else
                raw = initial;
                if ~isempty(expandedIds)
                    raw = HierarchicalHeightSolver.mergePlannedRaw( ...
                        initial, expansion, finalTiles(expandedIds, :), ...
                        finalTiles);
                else
                    raw.TilePlan = finalTiles;
                    raw.HeightLabelsByTile = finalTiles.HeightLabelsMetres;
                    raw.Runtime = adaptiveRuntime;
                end
                refinementTimer = tic;
                refined = HierarchicalHeightSolver.refinePlanned( ...
                    dense, raw, finalTiles, options.DeltaHeightMetres);
                refinementSeconds = toc(refinementTimer);
                finalBoundary = raw.Valid & (raw.LabelIndex == 1 ...
                    | raw.LabelIndex == raw.LabelCount);
            end

            if compact
                clear initial expansion inheritedProjection fineBoundary
                clear fineInvalid disagreement disagreementWarning dx dy
            end

            sgm = struct;
            sgmSeconds = 0;
            if options.RunSgm
                sgmTimer = tic;
                if streamedSgm
                    options.AggregateStore.synchronizePlan(finalTiles);
                    if compact
                        sgmProducts = "Margin";
                    else
                        sgmProducts = ["LabelIndex", "BestCost", ...
                            "SecondBestCost", "Margin"];
                    end
                    sgm = HeightSgm.aggregateTileLabelsStreamed( ...
                        options.CostStore, options.AggregateStore, ...
                        PenaltyPerMetre=options.PenaltyPerMetre, ...
                        MaximumPenalty=options.MaximumPenalty, ...
                        DirectionCount=options.DirectionCount, ...
                        ReturnAggregatedCost=options.RetainCostVolumes, ...
                        ReturnRawSelection=~compact, ...
                        ReturnTileIndex=false, Products=sgmProducts);
                else
                    sgm = HeightSgm.aggregateTileLabels( ...
                        finalTiles, raw.CostVolumesByTile, ...
                        PenaltyPerMetre=options.PenaltyPerMetre, ...
                        MaximumPenalty=options.MaximumPenalty, ...
                        DirectionCount=options.DirectionCount, ...
                        ReturnAggregatedCost=options.RetainCostVolumes);
                end
                sgmProjection = dense.projectHeightMap( ...
                    sgm.HeightMetres, sgm.Valid, ...
                    DeltaHeight=options.DeltaHeightMetres, ...
                    Products=projectionProducts);
                sgm.HeightMetres = sgmProjection.HeightMetres;
                sgm.CorrespondenceXY = sgmProjection.CorrespondenceXY;
                sgm.ObservabilityPixelsPerMetre = ...
                    sgmProjection.ObservabilityPixelsPerMetre;
                sgm.Valid = sgmProjection.Valid;
                if compact
                    [sgm.BoundaryWinnerCount, sgmValidCount] = ...
                        HierarchicalHeightSolver.heightBoundarySummary( ...
                        sgm.HeightMetres, sgm.Valid, finalTiles);
                    sgm.BoundaryWinnerFraction = ...
                        sgm.BoundaryWinnerCount ./ max(sgmValidCount, 1);
                    sgm = HierarchicalHeightSolver.compactAdaptiveSgm(sgm);
                end
                sgmSeconds = toc(sgmTimer);
            end
            if ~options.RetainCostVolumes && ~compact
                raw.CostVolumesByTile = cell(0, 1);
                raw.StoreCostVolumes = false;
            end
            if options.RunSgm
                if compact
                    finalSgmBoundary = false( ...
                        [referenceLevel.ImageSize, 0]);
                else
                    finalSgmBoundary = sgm.Valid ...
                        & (sgm.LabelIndex == 1 ...
                        | sgm.LabelIndex == raw.LabelCount);
                end
            else
                finalSgmBoundary = false(referenceLevel.ImageSize);
            end

            if hasCostStore
                costStoreStatistics = options.CostStore.statistics;
            else
                costStoreStatistics = struct;
            end
            if streamedSgm
                aggregateStoreStatistics = ...
                    options.AggregateStore.statistics;
            else
                aggregateStoreStatistics = struct;
            end

            fullReference = struct;
            fullSgmReference = struct;
            comparison = struct;
            sgmComparison = struct;
            referenceSeconds = 0;
            fullSgmSeconds = 0;
            if options.EvaluateFullReference
                geometryDiagnostic = HierarchicalHeightSolver.sampleGeometry( ...
                    geometry, double(plan.HeightRangeMetres), ...
                    options.ReferenceGeometrySampleGrid, ...
                    options.DeltaHeightMetres);
                labels = HierarchicalHeightSolver.heightLabels( ...
                    double(plan.HeightRangeMetres), ...
                    geometryDiagnostic.MedianObservabilityPixelsPerMetre, ...
                    plan.Settings.TargetProjectedMotionPixels);
                referenceTimer = tic;
                fullReference = dense.runZnccOptimized(labels, ...
                    TileSize=plan.Settings.TileSize, ...
                    LabelBlockSize=options.LabelBlockSize, ...
                    StoreCostVolumes=options.RunSgm, ...
                    UseParallel=options.UseParallel, ...
                    NumWorkers=options.NumWorkers, ...
                    MaximumPendingTiles=options.MaximumPendingTiles, ...
                    WorkingPrecision=obj.WorkingPrecision, ...
                    Products=["LabelIndex", "BestCost", ...
                    "SecondBestCost", "NeighborCosts", "Margin", ...
                    "Curvature", "ValidLabelCount", "Observability", ...
                    "Correspondence"], ...
                    DeltaHeight=options.DeltaHeightMetres, ...
                    MinimumSupportFraction=options.MinimumSupportFraction);
                referenceSeconds = toc(referenceTimer);
                comparison = HierarchicalHeightSolver.compareFine( ...
                    raw, fullReference);
                if options.RunSgm
                    fullSgmTimer = tic;
                    fullSgmReference = HeightSgm.aggregateVectorized( ...
                        fullReference.CostVolume, labels, ...
                        PenaltyPerMetre=options.PenaltyPerMetre, ...
                        MaximumPenalty=options.MaximumPenalty, ...
                        DirectionCount=options.DirectionCount);
                    fullSgmProjection = dense.projectHeightMap( ...
                        fullSgmReference.HeightMetres, ...
                        fullSgmReference.Valid, ...
                        DeltaHeight=options.DeltaHeightMetres);
                    fullSgmReference.HeightMetres = ...
                        fullSgmProjection.HeightMetres;
                    fullSgmReference.CorrespondenceXY = ...
                        fullSgmProjection.CorrespondenceXY;
                    fullSgmReference.ObservabilityPixelsPerMetre = ...
                        fullSgmProjection.ObservabilityPixelsPerMetre;
                    fullSgmReference.Valid = fullSgmProjection.Valid;
                    sgmComparison = HierarchicalHeightSolver.compareFine( ...
                        sgm, fullSgmReference);
                    if ~options.RetainCostVolumes
                        fullReference.CostVolume = zeros( ...
                            [referenceLevel.ImageSize, 0], ...
                            obj.WorkingPrecision);
                        fullReference.CostVolumeByChannel = struct;
                        fullReference.StoreCostVolumes = false;
                        fullSgmReference = ...
                            HierarchicalHeightSolver.compactSgm( ...
                            fullSgmReference);
                    end
                    fullSgmSeconds = toc(fullSgmTimer);
                end
            end

            if compact
                warnings = struct( ...
                    "MapsRetained", false, ...
                    "HighTrajectoryCurvatureTileCount", ...
                    nnz(highCurvature), ...
                    "UnderDenseTileCount", nnz(underDense), ...
                    "FineBoundaryWinnerBeforeExpansionCount", ...
                    fineBoundaryBeforeCount, ...
                    "FineInvalidOutputBeforeExpansionCount", ...
                    fineInvalidBeforeCount, ...
                    "CoarseFineDisagreementCount", ...
                    disagreementWarningCount, ...
                    "ExpansionTriggeredTileCount", ...
                    nnz(trigger.Triggered), ...
                    "ExpansionAppliedTileCount", ...
                    nnz(trigger.ExpansionApplied), ...
                    "FinalBoundaryWinnerCount", finalBoundaryCount, ...
                    "FinalBoundaryWinnerFraction", ...
                    finalBoundaryCount ./ max(finalRawValidCount, 1), ...
                    "FinalSgmBoundaryWinnerCount", ...
                    sgm.BoundaryWinnerCount, ...
                    "FinalSgmBoundaryWinnerFraction", ...
                    sgm.BoundaryWinnerFraction, ...
                    "TileTriggers", trigger, ...
                    "Policy", ...
                    "tile/count diagnostics retained; per-pixel warning maps omitted");
                fineInput = struct;
                initialTilePlan = table;
            else
                highCurvatureMap = ...
                    HierarchicalHeightSolver.tileFlagsToMap( ...
                    plan.Tiles, highCurvature, referenceLevel.ImageSize);
                underDenseMap = ...
                    HierarchicalHeightSolver.tileFlagsToMap( ...
                    plan.Tiles, underDense, referenceLevel.ImageSize);
                triggeredMap = ...
                    HierarchicalHeightSolver.tileFlagsToMap( ...
                    plan.Tiles, trigger.Triggered, ...
                    referenceLevel.ImageSize);
                expandedMap = ...
                    HierarchicalHeightSolver.tileFlagsToMap( ...
                    plan.Tiles, trigger.ExpansionApplied, ...
                    referenceLevel.ImageSize);
                warnings = struct( ...
                    "InheritedRawBoundary", ...
                    plan.Inherited.RawBoundaryWinner, ...
                    "InheritedSgmBoundary", ...
                    plan.Inherited.SgmBoundaryWinner, ...
                    "InheritedInvalidOutput", ...
                    plan.Inherited.InvalidOutput, ...
                    "InheritedLowConfidence", ...
                    plan.Inherited.LowConfidence, ...
                    "InheritedConfidenceInvalid", ...
                    plan.Inherited.ConfidenceInvalid, ...
                    "HighTrajectoryCurvature", highCurvatureMap, ...
                    "UnderDenseLabels", underDenseMap, ...
                    "FineBoundaryWinnerBeforeExpansion", fineBoundary, ...
                    "FineInvalidOutputBeforeExpansion", fineInvalid, ...
                    "CoarseFineDisagreementPixels", disagreement, ...
                    "CoarseFineDisagreement", disagreementWarning, ...
                    "ExpansionTriggered", triggeredMap, ...
                    "ExpansionApplied", expandedMap, ...
                    "FinalBoundaryWinner", finalBoundary, ...
                    "FinalSgmBoundaryWinner", finalSgmBoundary, ...
                    "TileTriggers", trigger, ...
                    "Policy", ...
                    "enabled warnings expand tile bands; warnings do not reject output");
                fineInput = struct( ...
                    "ReferenceImage", referenceLevel.Image, ...
                    "MovingImage", movingLevel.Image, ...
                    "ReferenceValid", referenceLevel.ValidMask, ...
                    "MovingValid", movingLevel.ValidMask);
                initialTilePlan = plan.Tiles;
            end

            result = struct( ...
                "Stage", "adaptive local-label fine ZNCC and refinement", ...
                "PreviousFactor", plan.PreviousFactor, ...
                "Factor", factor, ...
                "FineInput", fineInput, ...
                "InitialTilePlan", initialTilePlan, ...
                "FinalTilePlan", finalTiles, ...
                "Raw", raw, ...
                "Refined", refined, ...
                "Sgm", sgm, ...
                "Warnings", warnings, ...
                "FullCommonLabelReference", fullReference, ...
                "FullCommonLabelSgmReference", fullSgmReference, ...
                "ApproximationMetrics", comparison, ...
                "SgmApproximationMetrics", sgmComparison, ...
                "Persistence", struct( ...
                "Enabled", hasCostStore, ...
                "StreamedSgm", streamedSgm, ...
                "CostStore", options.CostStore, ...
                "AggregateStore", options.AggregateStore, ...
                "CostStoreStatistics", costStoreStatistics, ...
                "AggregateStoreStatistics", aggregateStoreStatistics), ...
                "Settings", struct( ...
                "OutputProfile", options.OutputProfile, ...
                "TargetProjectedMotionPixels", ...
                plan.Settings.TargetProjectedMotionPixels, ...
                "LabelBlockSize", options.LabelBlockSize, ...
                "GroupIdenticalBands", options.GroupIdenticalBands, ...
                "MaximumBandTiles", options.MaximumBandTiles, ...
                "MinimumSupportFraction", ...
                options.MinimumSupportFraction, ...
                "DeltaHeightMetres", options.DeltaHeightMetres, ...
                "ExpansionCoarseSteps", options.ExpansionCoarseSteps, ...
                "CoarseFineDisagreementPixels", ...
                options.CoarseFineDisagreementPixels, ...
                "MinimumDisagreementFraction", ...
                options.MinimumDisagreementFraction, ...
                "MinimumFineInvalidFraction", ...
                options.MinimumFineInvalidFraction, ...
                "HighTrajectoryCurvatureQuantile", ...
                options.HighTrajectoryCurvatureQuantile, ...
                "RunSgm", options.RunSgm, ...
                "PenaltyPerMetre", options.PenaltyPerMetre, ...
                "MaximumPenalty", options.MaximumPenalty, ...
                "DirectionCount", options.DirectionCount, ...
                "RetainCostVolumes", options.RetainCostVolumes, ...
                "EnabledTriggers", options.EnabledTriggers, ...
                "EvaluateFullReference", options.EvaluateFullReference), ...
                "Runtime", struct( ...
                "FirstPassSeconds", firstSeconds, ...
                "ExpansionSeconds", expansionSeconds, ...
                "RefinementSeconds", refinementSeconds, ...
                "SgmSeconds", sgmSeconds, ...
                "FullReferenceSeconds", referenceSeconds, ...
                "FullReferenceSgmSeconds", fullSgmSeconds, ...
                "FirstPassPixelLabelCount", ...
                adaptiveRuntime.FirstPassPixelLabelCount, ...
                "FirstPassBandCount", ...
                adaptiveRuntime.FirstPassBandCount, ...
                "ExpansionPixelLabelCount", ...
                adaptiveRuntime.ExpansionPixelLabelCount, ...
                "ExpansionBandCount", ...
                adaptiveRuntime.ExpansionBandCount, ...
                "EvaluatedPixelLabelCount", ...
                adaptiveRuntime.EvaluatedPixelLabelCount, ...
                "EvaluatedBandCount", ...
                adaptiveRuntime.EvaluatedBandCount, ...
                "ExpandedTileCount", numel(expandedIds), ...
                "TotalSeconds", toc(totalTimer)), ...
                "Approximation", ...
                "one common height grid per tile; one warning-driven expansion pass; optional seam-safe physical-height SGM", ...
                "WorldFrame", referenceCamera.WorldFrame, ...
                "ElevationDatum", referenceCamera.ElevationDatum);
        end
    end

    methods (Access = private)
        function [reference, moving] = levelCameras(obj, factor)
            if factor == 1
                reference = obj.ReferenceCamera;
                moving = obj.MovingCamera;
            else
                reference = PyramidLevelCamera(obj.ReferenceCamera, factor);
                moving = PyramidLevelCamera(obj.MovingCamera, factor);
            end
        end
    end

    methods (Static, Access = private)
        function validateAdaptiveStores( ...
                costStore, aggregateStore, runSgm, plan, precision)
            if ~isempty(costStore)
                if costStore.Precision ~= precision
                    error( ...
                        "HierarchicalHeightSolver:CostStorePrecisionMismatch", ...
                        "CostStore precision must equal WorkingPrecision.");
                end
                if ~isequal(costStore.Plan, plan)
                    error( ...
                        "HierarchicalHeightSolver:CostStorePlanMismatch", ...
                        "CostStore must begin with the exact fine tile plan.");
                end
                if costStore.statistics.WrittenTileCount ~= 0
                    error("HierarchicalHeightSolver:CostStoreNotEmpty", ...
                        "CostStore must be unwritten at the start of a run.");
                end
            end
            if isempty(aggregateStore)
                if runSgm && ~isempty(costStore)
                    error( ...
                        "HierarchicalHeightSolver:AggregateStoreRequired", ...
                        "Persistent adaptive SGM requires an AggregateStore.");
                end
                return
            end
            if ~runSgm || isempty(costStore)
                error("HierarchicalHeightSolver:UnusedAggregateStore", ...
                    "AggregateStore requires RunSgm=true and a CostStore.");
            end
            if aggregateStore.Precision ~= precision ...
                    || ~isequal(aggregateStore.Plan, plan) ...
                    || ~isequal(aggregateStore.Metadata, costStore.Metadata)
                error("HierarchicalHeightSolver:AggregateStoreMismatch", ...
                    ["AggregateStore must match the initial cost plan, " ...
                    "metadata, and precision."]);
            end
            if aggregateStore.statistics.WrittenTileCount ~= 0
                error("HierarchicalHeightSolver:AggregateStoreNotEmpty", ...
                    "AggregateStore must be unwritten at the start of a run.");
            end
        end

        function diagnostic = sampleGeometry( ...
                geometry, range, gridSize, deltaHeight)
            imageSize = geometry.ReferenceCamera.ImageSize;
            [y, x] = ndgrid(linspace(1, imageSize(1), gridSize(1)), ...
                linspace(1, imageSize(2), gridSize(2)));
            p = [x(:), y(:)];
            referenceInside = geometry.ReferenceCamera.isInsideImage(p);
            midpoint = mean(range);
            [t, kappa, valid] = geometry.heightDerivative( ...
                p, midpoint, DeltaHeight=deltaHeight);
            valid = valid & referenceInside & isfinite(kappa) & kappa > 0;
            if ~any(valid)
                error("HierarchicalHeightSolver:NoValidGeometrySamples", ...
                    "No valid overview dw/dz samples are available.");
            end
            kv = kappa(valid);
            diagnostic = struct( ...
                "SamplePixelXY", p, ...
                "HeightMidpointMetres", midpoint, ...
                "DeltaHeightMetres", deltaHeight, ...
                "HeightDerivativePixelsPerMetre", t, ...
                "ObservabilityPixelsPerMetre", kappa, ...
                "Valid", valid, ...
                "ValidFraction", mean(valid), ...
                "MedianObservabilityPixelsPerMetre", median(kv), ...
                "P10ObservabilityPixelsPerMetre", ...
                HierarchicalHeightSolver.percentile(kv, 10), ...
                "P90ObservabilityPixelsPerMetre", ...
                HierarchicalHeightSolver.percentile(kv, 90), ...
                "Definition", ...
                "central finite difference of exact level-camera warp");
        end

        function z = heightLabels(range, observability, target)
            count = max(3, ceil(diff(range) .* observability ./ target) + 1);
            z = linspace(range(1), range(2), count);
        end

        function sgm = compactSgm(sgm)
            remove = ["RawCost", "AggregatedCost", "ValidCandidate", ...
                "ValidDirectionCount", "PathCosts"];
            names = string(fieldnames(sgm));
            sgm = rmfield(sgm, cellstr(intersect(remove, names, "stable")));
        end

        function sgm = compactAdaptiveSgm(sgm)
            remove = ["HeightLabelsByTile", "TilePlan", "TileIndex", ...
                "RawCostByTile", "AggregatedCostByTile", ...
                "AggregateStore", "RawHeightMetres", "RawLabelIndex", ...
                "RawBestCost", "RawSecondBestCost", "RawCostMargin", ...
                "LabelIndex", "BestCost", "SecondBestCost", ...
                "ObservabilityPixelsPerMetre"];
            names = string(fieldnames(sgm));
            sgm = rmfield(sgm, ...
                cellstr(intersect(remove, names, "stable")));
            sgm.Products = ...
                ["Height", "Validity", "Margin", "Correspondence"];
            sgm.OutputProfile = "compact";
        end

        function runtime = mergeAdaptiveRuntime( ...
                first, expansion, finalTiles)
            runtime = first;
            runtime.FirstPassPixelLabelCount = first.PixelLabelCount;
            runtime.FirstPassBandCount = first.BandCount;
            if isempty(fieldnames(expansion))
                runtime.ExpansionPixelLabelCount = 0;
                runtime.ExpansionBandCount = 0;
                runtime.ExpansionTileCount = 0;
                runtime.EvaluatedPixelLabelCount = first.PixelLabelCount;
                runtime.EvaluatedBandCount = first.BandCount;
                return
            end

            patch = expansion.Runtime;
            sumNames = ["EvaluationSeconds", "PixelLabelCount", ...
                "GeometrySeconds", "BilinearSamplingSeconds", ...
                "LocalFilterSeconds", "WarpCalls", ...
                "WarpPointEvaluations", "BilinearSampleLocations", ...
                "LocalFilterOutputSamples"];
            for name = sumNames
                runtime.(name) = first.(name) + patch.(name);
            end
            runtime.PixelLabelsPerSecond = ...
                runtime.PixelLabelCount ./ runtime.EvaluationSeconds;
            runtime.ExpansionPixelLabelCount = patch.PixelLabelCount;
            runtime.EvaluatedPixelLabelCount = runtime.PixelLabelCount;
            runtime.ExpansionTileCount = patch.TileCount;
            runtime.EvaluatedTileCount = first.TileCount + patch.TileCount;
            runtime.ExpansionBandCount = patch.BandCount;
            runtime.EvaluatedBandCount = first.BandCount + patch.BandCount;
            runtime.GroupedTileCount = ...
                first.GroupedTileCount + patch.GroupedTileCount;
            runtime.MaximumBandTileCount = max( ...
                first.MaximumBandTileCount, patch.MaximumBandTileCount);
            runtime.MinimumLabelCount = min(finalTiles.LabelCount);
            runtime.MedianLabelCount = median(finalTiles.LabelCount);
            runtime.MaximumLabelCount = max(finalTiles.LabelCount);
            runtime.MaximumBlockResultBytes = max( ...
                first.MaximumBlockResultBytes, ...
                patch.MaximumBlockResultBytes);
            runtime.RetainedTileResultBytes = max( ...
                first.RetainedTileResultBytes, ...
                patch.RetainedTileResultBytes);
            runtime.RetainedTileResultCount = max( ...
                first.RetainedTileResultCount, ...
                patch.RetainedTileResultCount);
        end

        function [count, validCount] = finalRawBoundarySummary( ...
                initial, expansion, finalTiles, expandedIds)
            boundary = initial.Valid & (initial.LabelIndex == 1 ...
                | initial.LabelIndex == initial.LabelCount);
            count = nnz(boundary);
            validCount = nnz(initial.Valid);
            for k = 1:numel(expandedIds)
                id = expandedIds(k);
                rr = finalTiles.RowStart(id):finalTiles.RowEnd(id);
                cc = finalTiles.ColumnStart(id):finalTiles.ColumnEnd(id);
                count = count - nnz(boundary(rr, cc));
                validCount = validCount - nnz(initial.Valid(rr, cc));
                v = expansion.Valid(rr, cc);
                li = expansion.LabelIndex(rr, cc);
                count = count + nnz(v & (li == 1 ...
                    | li == finalTiles.LabelCount(id)));
                validCount = validCount + nnz(v);
            end
        end

        function [count, validCount] = heightBoundarySummary( ...
                heightMap, valid, tiles)
            count = 0;
            validCount = nnz(valid);
            for k = 1:height(tiles)
                rr = tiles.RowStart(k):tiles.RowEnd(k);
                cc = tiles.ColumnStart(k):tiles.ColumnEnd(k);
                v = valid(rr, cc);
                h = heightMap(rr, cc);
                z = tiles.HeightLabelsMetres{k};
                count = count + nnz(v & (h == z(1) | h == z(end)));
            end
        end

        function value = percentile(x, q)
            x = sort(x(isfinite(x)));
            position = 1 + (numel(x) - 1) .* q ./ 100;
            lo = floor(position);
            hi = ceil(position);
            value = x(lo) + (position - lo) .* (x(hi) - x(lo));
        end

        function value = optionalPercentile(x, q)
            if isempty(x)
                value = NaN;
            else
                value = HierarchicalHeightSolver.percentile(x, q);
            end
        end

        function n = precisionBytes(name)
            if name == "single"
                n = 4;
            else
                n = 8;
            end
        end

        function [value, valid, weight, clamped] = propagateField( ...
                source, sourceValid, nextSize, previousFactor, ...
                nextFactor, minimumSupport)
            [y, x] = ndgrid(1:nextSize(1), 1:nextSize(2));
            scale = nextFactor ./ previousFactor;
            qx = scale .* (x - 0.5) + 0.5;
            qy = scale .* (y - 0.5) + 0.5;
            clamped = qx < 1 | qx > size(source, 2) ...
                | qy < 1 | qy > size(source, 1);
            qx = min(max(qx, 1), size(source, 2));
            qy = min(max(qy, 1), size(source, 1));
            source = double(source);
            source(~sourceValid) = 0;
            weight = interp2(double(sourceValid), qx, qy, "linear", 0);
            numerator = interp2(source, qx, qy, "linear", 0);
            valid = weight >= minimumSupport;
            value = numerator ./ max(weight, eps);
            value(~valid) = NaN;
        end

        function warning = propagateWarning( ...
                source, nextSize, previousFactor, nextFactor)
            [y, x] = ndgrid(1:nextSize(1), 1:nextSize(2));
            scale = nextFactor ./ previousFactor;
            qx = min(max(scale .* (x - 0.5) + 0.5, 1), ...
                size(source, 2));
            qy = min(max(scale .* (y - 0.5) + 0.5, 1), ...
                size(source, 1));
            warning = interp2(double(source), qx, qy, "linear", 0) > 0;
        end

        function [trigger, highCurvature, underDense] = adaptiveTriggers( ...
                tiles, referenceValid, fineBoundary, fineInvalid, ...
                disagreement, options)
            count = height(tiles);
            fineBoundaryFraction = zeros(count, 1);
            fineInvalidFraction = zeros(count, 1);
            disagreementFraction = zeros(count, 1);
            for k = 1:count
                rr = tiles.RowStart(k):tiles.RowEnd(k);
                cc = tiles.ColumnStart(k):tiles.ColumnEnd(k);
                base = referenceValid(rr, cc);
                denominator = max(nnz(base), 1);
                fineBoundaryFraction(k) = nnz( ...
                    fineBoundary(rr, cc) & base) ./ denominator;
                fineInvalidFraction(k) = nnz( ...
                    fineInvalid(rr, cc) & base) ./ denominator;
                disagreementFraction(k) = nnz( ...
                    disagreement(rr, cc) & base) ./ denominator;
            end

            tc = tiles.P90TrajectoryCurvature;
            finiteTc = isfinite(tc);
            if any(finiteTc)
                curvatureThreshold = ...
                    HierarchicalHeightSolver.percentile(tc(finiteTc), ...
                    100 .* options.HighTrajectoryCurvatureQuantile);
                highCurvature = finiteTc & tc >= curvatureThreshold;
            else
                curvatureThreshold = NaN;
                highCurvature = false(count, 1);
            end
            intervalWidth = cellfun(@(z) z(end) - z(1), ...
                tiles.HeightLabelsMetres);
            actualMotion = intervalWidth ./ (tiles.LabelCount - 1) ...
                .* tiles.MedianObservabilityPixelsPerMetre;
            underDense = actualMotion > tiles.TargetProjectedMotionPixels ...
                + 32 .* eps(max(actualMotion, 1));

            enabled = options.EnabledTriggers;
            rawBoundary = tiles.RawBoundaryFraction > 0 ...
                & any(enabled == "InheritedRawBoundary");
            sgmBoundary = tiles.SgmBoundaryFraction > 0 ...
                & any(enabled == "InheritedSgmBoundary");
            inheritedInvalid = tiles.InvalidOutputFraction > 0 ...
                & any(enabled == "InheritedInvalidOutput");
            lowConfidence = tiles.LowConfidenceFraction > 0 ...
                & any(enabled == "InheritedLowConfidence");
            confidenceInvalid = tiles.ConfidenceInvalidFraction > 0 ...
                & any(enabled == "InheritedConfidenceInvalid");
            curvature = highCurvature ...
                & any(enabled == "HighTrajectoryCurvature");
            density = underDense & any(enabled == "UnderDenseLabels");
            boundary = fineBoundaryFraction > 0 ...
                & any(enabled == "FineBoundaryWinner");
            invalid = fineInvalidFraction ...
                > options.MinimumFineInvalidFraction ...
                & any(enabled == "FineInvalidOutput");
            disagree = disagreementFraction ...
                > options.MinimumDisagreementFraction ...
                & any(enabled == "CoarseFineDisagreement");
            triggered = rawBoundary | sgmBoundary | inheritedInvalid ...
                | lowConfidence | confidenceInvalid | curvature | density ...
                | boundary | invalid | disagree;

            trigger = table(tiles.Tile, ...
                tiles.RawBoundaryFraction, rawBoundary, ...
                tiles.SgmBoundaryFraction, sgmBoundary, ...
                tiles.InvalidOutputFraction, inheritedInvalid, ...
                tiles.LowConfidenceFraction, lowConfidence, ...
                tiles.ConfidenceInvalidFraction, confidenceInvalid, ...
                tc, repmat(curvatureThreshold, count, 1), curvature, ...
                actualMotion, density, fineBoundaryFraction, boundary, ...
                fineInvalidFraction, invalid, disagreementFraction, ...
                disagree, triggered, VariableNames=["Tile", ...
                "InheritedRawBoundaryFraction", ...
                "InheritedRawBoundaryTrigger", ...
                "InheritedSgmBoundaryFraction", ...
                "InheritedSgmBoundaryTrigger", ...
                "InheritedInvalidOutputFraction", ...
                "InheritedInvalidOutputTrigger", ...
                "InheritedLowConfidenceFraction", ...
                "InheritedLowConfidenceTrigger", ...
                "InheritedConfidenceInvalidFraction", ...
                "InheritedConfidenceInvalidTrigger", ...
                "P90TrajectoryCurvature", ...
                "TrajectoryCurvatureThreshold", ...
                "HighTrajectoryCurvatureTrigger", ...
                "ActualProjectedMotionPixels", ...
                "UnderDenseLabelsTrigger", ...
                "FineBoundaryFraction", "FineBoundaryTrigger", ...
                "FineInvalidFraction", "FineInvalidTrigger", ...
                "CoarseFineDisagreementFraction", ...
                "CoarseFineDisagreementTrigger", "Triggered"]);
        end

        function [tiles, trigger] = expandTiles( ...
                tiles, trigger, globalRange, expansionCoarseSteps)
            count = height(tiles);
            initialMinimum = tiles.MinimumHeightMetres;
            initialMaximum = tiles.MaximumHeightMetres;
            finalMinimum = initialMinimum;
            finalMaximum = initialMaximum;
            applied = false(count, 1);
            for k = 1:count
                if ~trigger.Triggered(k)
                    continue
                end
                coarseStep = 2 .* tiles.CoarseHalfLabelStepMetres(k);
                padding = expansionCoarseSteps .* coarseStep;
                finalMinimum(k) = max(globalRange(1), ...
                    initialMinimum(k) - padding);
                finalMaximum(k) = min(globalRange(2), ...
                    initialMaximum(k) + padding);
                applied(k) = finalMinimum(k) < initialMinimum(k) ...
                    || finalMaximum(k) > initialMaximum(k);
                if applied(k)
                    labelCount = max(3, ceil( ...
                        (finalMaximum(k) - finalMinimum(k)) ...
                        .* tiles.MedianObservabilityPixelsPerMetre(k) ...
                        ./ tiles.TargetProjectedMotionPixels(k)) + 1);
                    z = linspace(finalMinimum(k), finalMaximum(k), ...
                        labelCount);
                    tiles.MinimumHeightMetres(k) = finalMinimum(k);
                    tiles.MaximumHeightMetres(k) = finalMaximum(k);
                    tiles.LabelCount(k) = labelCount;
                    tiles.ActualMedianProjectedMotionPixels(k) = ...
                        diff([finalMinimum(k), finalMaximum(k)]) ...
                        ./ (labelCount - 1) ...
                        .* tiles.MedianObservabilityPixelsPerMetre(k);
                    tiles.HeightLabelsMetres{k} = z;
                end
            end
            trigger.InitialMinimumHeightMetres = initialMinimum;
            trigger.InitialMaximumHeightMetres = initialMaximum;
            trigger.FinalMinimumHeightMetres = finalMinimum;
            trigger.FinalMaximumHeightMetres = finalMaximum;
            trigger.LowerExpansionMetres = initialMinimum - finalMinimum;
            trigger.UpperExpansionMetres = finalMaximum - initialMaximum;
            trigger.ExpansionApplied = applied;
        end

        function raw = mergePlannedRaw(initial, patch, patchPlan, allPlan)
            raw = initial;
            fields = ["HeightMetres", "Valid", "LabelIndex", ...
                "BestCost", "SecondBestCost", "CostMargin", ...
                "PreviousLabelCost", "NextLabelCost", ...
                "LocalCurvaturePerMetreSquared", "ValidLabelCount", ...
                "ValidLabelFraction", "ObservabilityPixelsPerMetre", ...
                "LabelCount"];
            for k = 1:height(patchPlan)
                rr = patchPlan.RowStart(k):patchPlan.RowEnd(k);
                cc = patchPlan.ColumnStart(k):patchPlan.ColumnEnd(k);
                for name = fields
                    raw.(name)(rr, cc) = patch.(name)(rr, cc);
                end
                raw.CorrespondenceXY(rr, cc, :) = ...
                    patch.CorrespondenceXY(rr, cc, :);
                raw.SelectedHeightByChannel.Zncc(rr, cc) = ...
                    patch.SelectedHeightByChannel.Zncc(rr, cc);
                if initial.StoreCostVolumes
                    originalRow = find(allPlan.Tile == patchPlan.Tile(k), 1);
                    raw.CostVolumesByTile{originalRow} = ...
                        patch.CostVolumesByTile{k};
                end
            end
            raw.TilePlan = allPlan;
            raw.HeightLabelsByTile = allPlan.HeightLabelsMetres;
            raw.Approximation = ...
                "one exact common height-label vector per tile after selective expansion";
            sumNames = ["EvaluationSeconds", "PixelLabelCount", ...
                "GeometrySeconds", "BilinearSamplingSeconds", ...
                "LocalFilterSeconds", "WarpCalls", ...
                "WarpPointEvaluations", "BilinearSampleLocations", ...
                "LocalFilterOutputSamples"];
            for name = sumNames
                raw.Runtime.(name) = initial.Runtime.(name) ...
                    + patch.Runtime.(name);
            end
            raw.Runtime.PixelLabelsPerSecond = ...
                raw.Runtime.PixelLabelCount ...
                ./ raw.Runtime.EvaluationSeconds;
            raw.Runtime.FirstPassPixelLabelCount = ...
                initial.Runtime.PixelLabelCount;
            raw.Runtime.ExpansionPixelLabelCount = ...
                patch.Runtime.PixelLabelCount;
            raw.Runtime.EvaluatedPixelLabelCount = ...
                raw.Runtime.PixelLabelCount;
            raw.Runtime.ExpansionTileCount = height(patchPlan);
            raw.Runtime.EvaluatedTileCount = ...
                initial.Runtime.TileCount + patch.Runtime.TileCount;
            raw.Runtime.FirstPassBandCount = initial.Runtime.BandCount;
            raw.Runtime.ExpansionBandCount = patch.Runtime.BandCount;
            raw.Runtime.EvaluatedBandCount = ...
                initial.Runtime.BandCount + patch.Runtime.BandCount;
            raw.Runtime.GroupedTileCount = ...
                initial.Runtime.GroupedTileCount ...
                + patch.Runtime.GroupedTileCount;
            raw.Runtime.MaximumBandTileCount = max( ...
                initial.Runtime.MaximumBandTileCount, ...
                patch.Runtime.MaximumBandTileCount);
            raw.Runtime.MinimumLabelCount = min(allPlan.LabelCount);
            raw.Runtime.MedianLabelCount = median(allPlan.LabelCount);
            raw.Runtime.MaximumLabelCount = max(allPlan.LabelCount);
            raw.Runtime.MaximumBlockResultBytes = max( ...
                initial.Runtime.MaximumBlockResultBytes, ...
                patch.Runtime.MaximumBlockResultBytes);
            raw.Runtime.RetainedTileResultBytes = max( ...
                initial.Runtime.RetainedTileResultBytes, ...
                patch.Runtime.RetainedTileResultBytes);
            raw.Runtime.RetainedTileResultCount = max( ...
                initial.Runtime.RetainedTileResultCount, ...
                patch.Runtime.RetainedTileResultCount);
        end

        function refined = refinePlanned(dense, raw, tiles, deltaHeight)
            imageSize = size(raw.HeightMetres);
            discrete = nan(imageSize);
            refinedHeight = nan(imageSize);
            offset = nan(imageSize);
            curvature = nan(imageSize);
            valid = false(imageSize);
            interior = false(imageSize);
            finiteNeighbors = false(imageSize);
            positiveCurvature = false(imageSize);
            withinInterval = false(imageSize);
            for k = 1:height(tiles)
                rr = tiles.RowStart(k):tiles.RowEnd(k);
                cc = tiles.ColumnStart(k):tiles.ColumnEnd(k);
                r = HeightSublabelRefiner.refine( ...
                    double(tiles.HeightLabelsMetres{k}), ...
                    double(raw.LabelIndex(rr, cc)), ...
                    double(raw.PreviousLabelCost(rr, cc)), ...
                    double(raw.BestCost(rr, cc)), ...
                    double(raw.NextLabelCost(rr, cc)), ...
                    ValidMask=raw.Valid(rr, cc));
                discrete(rr, cc) = r.DiscreteHeightMetres;
                refinedHeight(rr, cc) = r.RefinedHeightMetres;
                offset(rr, cc) = r.OffsetMetres;
                curvature(rr, cc) = r.CurvaturePerMetreSquared;
                valid(rr, cc) = r.Valid;
                interior(rr, cc) = r.InteriorMinimum;
                finiteNeighbors(rr, cc) = r.FiniteNeighbors;
                positiveCurvature(rr, cc) = r.PositiveCurvature;
                withinInterval(rr, cc) = r.WithinNeighborInterval;
            end
            projection = dense.projectHeightMap( ...
                refinedHeight, valid, DeltaHeight=deltaHeight);
            refined = struct( ...
                "DiscreteHeightMetres", discrete, ...
                "RefinedHeightMetres", projection.HeightMetres, ...
                "HeightMetres", projection.HeightMetres, ...
                "OffsetMetres", offset, ...
                "CurvaturePerMetreSquared", curvature, ...
                "RefinementValidBeforeProjection", valid, ...
                "Valid", projection.Valid, ...
                "InteriorMinimum", interior, ...
                "FiniteNeighbors", finiteNeighbors, ...
                "PositiveCurvature", positiveCurvature, ...
                "WithinNeighborInterval", withinInterval, ...
                "CorrespondenceXY", projection.CorrespondenceXY, ...
                "ObservabilityPixelsPerMetre", ...
                projection.ObservabilityPixelsPerMetre, ...
                "FailurePolicy", ...
                "invalid refinement; discrete adaptive height remains separate");
        end

        function comparison = compareFine(adaptive, reference)
            joint = adaptive.Valid & reference.Valid;
            dx = adaptive.CorrespondenceXY(:, :, 1) ...
                - reference.CorrespondenceXY(:, :, 1);
            dy = adaptive.CorrespondenceXY(:, :, 2) ...
                - reference.CorrespondenceXY(:, :, 2);
            epe = hypot(dx(joint), dy(joint));
            dh = adaptive.HeightMetres(joint) ...
                - reference.HeightMetres(joint);
            comparison = struct( ...
                "ReferenceValidPixelCount", nnz(reference.Valid), ...
                "AdaptiveValidPixelCount", nnz(adaptive.Valid), ...
                "JointValidPixelCount", nnz(joint), ...
                "MissedReferencePixelCount", ...
                nnz(reference.Valid & ~adaptive.Valid), ...
                "AdditionalAdaptivePixelCount", ...
                nnz(adaptive.Valid & ~reference.Valid), ...
                "ValidityAgreementFraction", ...
                mean(adaptive.Valid == reference.Valid, "all"), ...
                "CorrespondenceEpeRmsePixels", ...
                HierarchicalHeightSolver.rmse(epe), ...
                "CorrespondenceEpeP95Pixels", ...
                HierarchicalHeightSolver.optionalPercentile(epe, 95), ...
                "HeightDifferenceRmseMetres", ...
                HierarchicalHeightSolver.rmse(dh), ...
                "Definition", ...
                "adaptive unregularized WTA minus full common-label unregularized WTA");
        end

        function map = tileFlagsToMap(tiles, flag, imageSize)
            map = false(imageSize);
            for k = find(flag(:)).'
                rr = tiles.RowStart(k):tiles.RowEnd(k);
                cc = tiles.ColumnStart(k):tiles.ColumnEnd(k);
                map(rr, cc) = true;
            end
        end

        function n = optionalRuntimeCount(result, name)
            if isempty(fieldnames(result))
                n = 0;
            else
                n = result.Runtime.(name);
            end
        end

        function value = rmse(x)
            if isempty(x)
                value = NaN;
            else
                value = sqrt(mean(x .^ 2));
            end
        end

        function tiles = planTiles(geometry, height, heightValid, ...
                sigmaHeight, confidenceValid, rawBoundary, sgmBoundary, ...
                invalidOutput, lowConfidence, confidenceInvalid, ...
                globalRange, coarseLabels, options)
            imageSize = size(height);
            rowStarts = 1:options.TileSize(1):imageSize(1);
            columnStarts = 1:options.TileSize(2):imageSize(2);
            count = numel(rowStarts) .* numel(columnStarts);
            rows = cell(count, 32);
            coarseHalfStep = 0.5 .* median(diff(coarseLabels));
            tile = 0;
            for rowStart = rowStarts
                rowEnd = min(rowStart + options.TileSize(1) - 1, ...
                    imageSize(1));
                for columnStart = columnStarts
                    columnEnd = min(columnStart + options.TileSize(2) - 1, ...
                        imageSize(2));
                    tile = tile + 1;
                    rr = rowStart:rowEnd;
                    cc = columnStart:columnEnd;
                    hv = heightValid(rr, cc);
                    h = height(rr, cc);
                    h = h(hv & isfinite(h));
                    cv = confidenceValid(rr, cc);
                    sh = sigmaHeight(rr, cc);
                    sh = sh(cv & isfinite(sh));

                    [gy, gx] = ndgrid(linspace(rowStart, rowEnd, ...
                        options.GeometrySampleGrid(1)), ...
                        linspace(columnStart, columnEnd, ...
                        options.GeometrySampleGrid(2)));
                    gp = [gx(:), gy(:)];
                    if isempty(h)
                        gh = repmat(mean(globalRange), size(gp, 1), 1);
                    else
                        gh = interp2(height, gx(:), gy(:), "linear", NaN);
                        gh(~isfinite(gh)) = median(h);
                    end
                    [~, kappa, gv] = geometry.heightDerivative( ...
                        gp, gh, DeltaHeight=options.DeltaHeightMetres);
                    gv = gv & isfinite(kappa) & kappa > 0;
                    d = options.TrajectoryCurvatureDeltaHeightMetres;
                    [wm, vm] = geometry.warp(gp, gh - d);
                    [w0, v0] = geometry.warp(gp, gh);
                    [wp, vp] = geometry.warp(gp, gh + d);
                    tc = vecnorm(wp - 2 .* w0 + wm, 2, 2) ...
                        ./ max(vecnorm(wp - wm, 2, 2), eps);
                    tv = vm & v0 & vp & isfinite(tc);
                    fallback = isempty(h) || ~any(gv);
                    if fallback
                        interval = globalRange;
                        inheritedMinimum = NaN;
                        inheritedMaximum = NaN;
                        confidencePadding = NaN;
                        medianKappa = median(kappa(gv), "omitmissing");
                    else
                        inheritedMinimum = min(h);
                        inheritedMaximum = max(h);
                        if isempty(sh)
                            confidencePadding = 0;
                        else
                            confidencePadding = ...
                                options.ConfidenceSigmaMultiplier ...
                                .* HierarchicalHeightSolver.percentile( ...
                                sh, options.ConfidenceHeightPercentile);
                        end
                        padding = coarseHalfStep + confidencePadding;
                        interval = [max(globalRange(1), ...
                            inheritedMinimum - padding), ...
                            min(globalRange(2), ...
                            inheritedMaximum + padding)];
                        medianKappa = median(kappa(gv));
                    end
                    if ~isfinite(medianKappa) || medianKappa <= 0 ...
                            || interval(2) <= interval(1)
                        fallback = true;
                        interval = globalRange;
                        validKappa = kappa(gv);
                        if isempty(validKappa)
                            error("HierarchicalHeightSolver:InvalidTileGeometry", ...
                                "Tile %d has no valid dw/dz samples.", tile);
                        end
                        medianKappa = median(validKappa);
                    end
                    labelCount = max(3, ceil(diff(interval) .* medianKappa ...
                        ./ options.TargetProjectedMotionPixels) + 1);
                    labels = linspace(interval(1), interval(2), labelCount);
                    actualMotion = diff(interval) ./ (labelCount - 1) ...
                        .* medianKappa;
                    pixelCount = numel(rr) .* numel(cc);
                    rows(tile, :) = {tile, rowStart, rowEnd, columnStart, ...
                        columnEnd, pixelCount, nnz(hv) ./ pixelCount, ...
                        inheritedMinimum, inheritedMaximum, ...
                        nnz(cv) ./ pixelCount, confidencePadding, ...
                        mean(rawBoundary(rr, cc), "all"), ...
                        mean(sgmBoundary(rr, cc), "all"), ...
                        mean(invalidOutput(rr, cc), "all"), ...
                        mean(lowConfidence(rr, cc), "all"), ...
                        mean(confidenceInvalid(rr, cc), "all"), ...
                        mean(gv), medianKappa, ...
                        HierarchicalHeightSolver.percentile(kappa(gv), 10), ...
                        HierarchicalHeightSolver.percentile(kappa(gv), 90), ...
                        mean(tv), ...
                        HierarchicalHeightSolver.optionalPercentile(tc(tv), 50), ...
                        HierarchicalHeightSolver.optionalPercentile(tc(tv), 90), ...
                        d, ...
                        interval(1), interval(2), coarseHalfStep, ...
                        options.TargetProjectedMotionPixels, labelCount, ...
                        actualMotion, {labels}, fallback};
                end
            end
            tiles = cell2table(rows, VariableNames=["Tile", "RowStart", ...
                "RowEnd", "ColumnStart", "ColumnEnd", "PixelCount", ...
                "InheritedValidFraction", "InheritedMinimumHeightMetres", ...
                "InheritedMaximumHeightMetres", "ConfidenceValidFraction", ...
                "ConfidencePaddingMetres", "RawBoundaryFraction", ...
                "SgmBoundaryFraction", "InvalidOutputFraction", ...
                "LowConfidenceFraction", "ConfidenceInvalidFraction", ...
                "GeometryValidFraction", ...
                "MedianObservabilityPixelsPerMetre", ...
                "P10ObservabilityPixelsPerMetre", ...
                "P90ObservabilityPixelsPerMetre", ...
                "TrajectoryGeometryValidFraction", ...
                "MedianTrajectoryCurvature", ...
                "P90TrajectoryCurvature", ...
                "TrajectoryCurvatureDeltaHeightMetres", ...
                "MinimumHeightMetres", "MaximumHeightMetres", ...
                "CoarseHalfLabelStepMetres", ...
                "TargetProjectedMotionPixels", "LabelCount", ...
                "ActualMedianProjectedMotionPixels", ...
                "HeightLabelsMetres", "FallbackGlobalBounds"]);
        end
    end
end

function mustBeHierarchyCamera(camera)
if ~(isa(camera, "PinholeCamera") || isa(camera, "Rpc00bCamera") ...
        || isa(camera, "RpcImageCorrectionCamera") ...
        || isa(camera, "RpcImageWindowCamera"))
    error("HierarchicalHeightSolver:UnsupportedCamera", ...
        "Camera must implement a supported hierarchy camera contract.");
end
end

function mustMatchCameraSize(image, camera)
if ~isequal(size(image), camera.ImageSize)
    error("HierarchicalHeightSolver:ImageSizeMismatch", ...
        "Each image must match its camera ImageSize.");
end
end

function mustBeFineTilePlan(plan)
required = ["PreviousFactor", "NextFactor", "NextReferenceSize", ...
    "NextMovingSize", "HeightRangeMetres", "Inherited", "Tiles", ...
    "Settings"];
if ~all(isfield(plan, required)) ...
        || ~isstruct(plan.Inherited) || ~istable(plan.Tiles) ...
        || ~isstruct(plan.Settings) ...
        || ~isfield(plan.Settings, "TargetProjectedMotionPixels") ...
        || ~isfield(plan.Settings, "TileSize")
    error("HierarchicalHeightSolver:InvalidFinePlan", ...
        "Fine plan must be an unmodified PREPARENEXTLEVEL result.");
end
end

function mustBeAdaptiveTriggers(names)
allowed = ["InheritedRawBoundary", "InheritedSgmBoundary", ...
    "InheritedInvalidOutput", "InheritedLowConfidence", ...
    "InheritedConfidenceInvalid", "HighTrajectoryCurvature", ...
    "UnderDenseLabels", "FineBoundaryWinner", "FineInvalidOutput", ...
    "CoarseFineDisagreement"];
mustBeMember(names, allowed);
if numel(unique(names)) ~= numel(names)
    error("HierarchicalHeightSolver:DuplicateAdaptiveTrigger", ...
        "EnabledTriggers must not contain duplicate names.");
end
end

function mustBeOptionalHeightTileStore(store)
if ~isempty(store) ...
        && (~isa(store, "HeightTileStore") || ~isscalar(store))
    error("HierarchicalHeightSolver:InvalidHeightTileStore", ...
        ["CostStore and AggregateStore must be empty or scalar " ...
        "HeightTileStore objects."]);
end
end

function mustMatchImageSize(mask, image)
if ~isequal(size(mask), size(image))
    error("HierarchicalHeightSolver:MaskSizeMismatch", ...
        "Each validity mask must match its image.");
end
end

function mustBeOptionalPyramidFactors(factors)
if isempty(factors)
    return
end
valid = all(isfinite(factors)) && all(factors > 0) ...
    && all(factors == fix(factors)) && factors(end) == 1 ...
    && all(diff(factors) < 0);
if ~valid
    error("HierarchicalHeightSolver:InvalidPyramidFactors", ...
        "Explicit factors must be descending positive integers ending at one.");
end
end

function mustBeIncreasingRange(range)
if range(2) <= range(1)
    error("HierarchicalHeightSolver:InvalidHeightRange", ...
        "Height range must be strictly increasing.");
end
end
